import { Link } from "react-router-dom";

export default function Navbar() {
  return (
    <nav style={{ padding: "10px", background: "#1e293b" }}>
      <Link to="/leads" style={link}>Leads</Link>
      <Link to="/vehicles" style={link}>Vehicles</Link>
      <Link to="/users" style={link}>Users</Link>
    </nav>
  );
}

const link = {
  color: "white",
  marginRight: "15px",
  textDecoration: "none"
};
